# @cctt_verify {"v":2,"sym":"sympy.functions.special.tests.test_bessel.test_besselk_leading_term","kind":"function","src_hash":"887e61bc61a51d9f","in":{"base":"Any"},"out":{"base":"Any","pred":"besselk(0, x).as_leading_term(x) == -log(x) - S.EulerGamma + log(2) and besselk(1, sin(x)).as_leading_term(x) == 1 / x and besselk(1, 2 * sqrt(x)).as_leading_term(x) == 1 / (2 * sqrt(x)) and besselk(1, cos(x)).as_leading_term(x) == besselk(1, 1) and besselk(3, 1 / x).as_leading_term(x) == sqrt(pi) * exp(-(1 / x)) / sqrt(2 / x)"},"spec":{"lhs":"test_besselk_leading_term()","rhs":"test_besselk_leading_term produces the expected output","over":{"base":"Any"},"name":"test_besselk_leading_term_correct"},"guarantee":"test_besselk_leading_term produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.special.tests.test_bessel.test_besselk_leading_term_correct","statement":"Path(test_besselk_leading_term(x), test_besselk_leading_term produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"09b2dd9eb0a91d12"}
def test_besselk_leading_term():
    assert besselk(0, x).as_leading_term(x) == -log(x) - S.EulerGamma + log(2)
    assert besselk(1, sin(x)).as_leading_term(x) == 1/x
    assert besselk(1, 2*sqrt(x)).as_leading_term(x) == 1/(2*sqrt(x))
    assert besselk(S(5)/3, x).as_leading_term(x) == 2**(S(2)/3)*gamma(S(5)/3)/x**(S(5)/3)
    assert besselk(S(2)/3, x).as_leading_term(x) == besselk(-S(2)/3, x).as_leading_term(x)
    assert besselk(1,cos(x)).as_leading_term(x) == besselk(1,1)
    assert besselk(3,1/x).as_leading_term(x) == sqrt(pi)*exp(-(1/x))/sqrt(2/x)
    assert besselk(3,1/sin(x)).as_leading_term(x) == sqrt(pi)*exp(-(1/x))/sqrt(2/x)

    nz = Symbol("nz", nonzero=True)
    assert besselk(nz, x).as_leading_term(x).subs({nz:S(5)/7}) == besselk(S(5)/7, x).series(x).as_leading_term(x)
    assert besselk(nz, x).as_leading_term(x).subs({nz:S(-15)/7}) == besselk(S(-15)/7, x).series(x).as_leading_term(x)
    assert besselk(nz, x).as_leading_term(x).subs({nz:3}) == besselk(3, x).series(x).as_leading_term(x)
    assert besselk(nz, x).as_leading_term(x).subs({nz:-2}) == besselk(-2, x).series(x).as_leading_term(x)


